CREATE OR REPLACE EDITIONABLE PACKAGE "%USER_NAME%"."MAXPRINT_JSON_UTILS_V2" AS

    FUNCTION GET_JSON_FROM_SQL (P_SQL IN CLOB, P_SQL_TYPE VARCHAR2, P_QUERY_MASTER_COLS VARCHAR2 DEFAULT NULL) RETURN CLOB;
    FUNCTION GET_JSON_FROM_PLSQL (PL_CODE IN CLOB, P_DATASOURE_TYPE VARCHAR2) RETURN CLOB;
    FUNCTION GET_JSON_FROM_REGION (P_APP_ID NUMBER,P_PAGE_ID NUMBER,P_REGION_STATIC_ID VARCHAR2) RETURN CLOB;
    FUNCTION GET_JSON_FROM_REFCURSOR (P_REFCURSOR IN SYS_REFCURSOR) RETURN CLOB;

END "MAXPRINT_JSON_UTILS_V2";
/
